      "title": "AI面试算法题示例",
      "code": "# AI面试常考的算法题示例\n# 题目：使用二分查找在旋转排序数组中查找目标值\n\ndef search_rotated(nums, target):\n    if not nums:\n        return -1\n    left, right = 0, len(nums) - 1\n    while left <= right:\n        mid = (left + right) // 2\n        if nums[mid] == target:\n            return mid\n        if nums[left] <= nums[mid]:\n            if nums[left] <= target < nums[mid]:\n                right = mid - 1\n            else:\n                left = mid + 1\n        else:\n            if nums[mid] < target <= nums[right]:\n                left = mid + 1\n            else:\n                right = mid - 1\n    return -1\n\ntest_cases = [\n    ([4,5,6,7,0,1,2], 0, 4),\n    ([4,5,6,7,0,1,2], 3, -1),\n    ([1], 0, -1),\n]\nfor nums, target, expected in test_cases:\n    result = search_rotated(nums, target)\n    print(f\"search_rotated({nums}, {target}) = {result} (expected {expected})\")"
