        "code": "# ToT (Tree of Thought) 实现\nimport random\n\nclass ToT:\n    def __init__(self, llm, max_depth=3):\n        self.llm = llm\n        self.max_depth = max_depth\n\n    def generate(self, node):\n        \"\"\"生成多个候选\"\"\"\n        prompt = f\"Task: {node['task']}\\nCurrent: {node['thought']}\\nGenerate 3 different solutions:\"\n        response = self.llm.generate(prompt)\n        candidates = response.split(\"\\n\")[:3]\n        return [{\"task\": node[\"task\"], \"thought\": c} for c in candidates]\n\n    def evaluate(self, node):\n        \"\"\"评估候选质量\"\"\"\n        prompt = f\"Evaluate: {node['thought']}\\nScore 0-10:\"\n        score = self.llm.generate(prompt)\n        return int(score.strip())\n\n    def search(self, task):\n        \"\"\"ToT 搜索\"\"\"\n        root = {\"task\": task, \"thought\": \"Start thinking...\"}\n        frontier = [root]\n        \n        for depth in range(self.max_depth):\n            new_frontier = []\n            for node in frontier:\n                candidates = self.generate(node)\n                for c in candidates:\n                    c[\"score\"] = self.evaluate(c)\n                    new_frontier.append(c)\n            \n            # 选择 top-k\n            frontier = sorted(new_frontier, key=lambda x: x[\"score\"], reverse=True)[:5]\n        \n        return frontier[0][\"thought\"]\n\nprint(\"=== ToT 搜索 ===\")\nprint(\"1. 生成多个候选\")\nprint(\"2. 评估候选\")\nprint(\"3. 选择 top-k\")\nprint(\"4. 递归直到深度上限\")\nprint(\"5. 返回最优\")",
