      "code": "import numba\nimport numpy as np\nimport time\n\n# 纯 Python 函数\ndef sum_square_py(arr):\n    total = 0.0\n    for i in range(len(arr)):\n        total += arr[i] ** 2\n    return total\n\n# Numba JIT 编译\n@numba.njit\ndef sum_square_numba(arr):\n    total = 0.0\n    for i in range(len(arr)):\n        total += arr[i] ** 2\n    return total\n\n# 生成数据\nsize = 10_000_000\narr = np.random.rand(size)\n\n# 测试 Python 版本\nstart = time.perf_counter()\nresult_py = sum_square_py(arr)\npy_time = time.perf_counter() - start\n\n# 测试 Numba 版本\nstart = time.perf_counter()\nresult_numba = sum_square_numba(arr)\nnumba_time = time.perf_counter() - start\n\nprint(f\"Python: {py_time:.4f}s\")\nprint(f\"Numba: {numba_time:.4f}s\")\nprint(f\"Speedup: {py_time / numba_time:.1f}x\")",
