      "code": "import numpy as np\nfrom sentence_transformers import SentenceTransformer\n\n# 加载模型\nmodel = SentenceTransformer('BAAI/bge-small-zh-v1.5')\n\n# 句子列表\nsentences = [\n    \"今天天气真好\",\n    \"机器学习很有趣\",\n    \"Python 是数据科学的首选语言\"\n]\n\n# 获取嵌入\nembeddings = model.encode(sentences, normalize_embeddings=True)\nprint(f\"Embeddings shape: {embeddings.shape}\")  # (3, 384)\n\n# L2 归一化（如果模型未归一化）\nembeddings = embeddings / np.linalg.norm(embeddings, axis=1, keepdims=True)\n\n# 计算余弦相似度矩阵\nsimilarity = np.dot(embeddings, embeddings.T)\nprint(f\"Similarity matrix:\\n{similarity}\")\n\n# 保存为 FAISS 索引\nimport faiss\ndim = embeddings.shape[1]\nindex = faiss.IndexFlatIP(dim)  # 内积索引（等价于余弦相似度）\nindex.add(embeddings.astype(np.float32))\n\n# 搜索最相似句子\nquery = model.encode([\"人工智能\"], normalize_embeddings=True)\ndistances, indices = index.search(query.astype(np.float32), k=2)\nprint(f\"Top 2 similar indices: {indices}\")",
