      "code": "# TruLens Context Relevance 示例\nfrom trulens_eval import Feedback, TruLlama\nfrom trulens_eval.feedback.provider import OpenAI\nimport numpy as np\n\n# 初始化 OpenAI provider\nprovider = OpenAI(model_engine=\"gpt-4\")\n\n# 定义 Context Relevance 反馈函数\ncontext_relevance = Feedback(\n    provider.context_relevance_with_cot_reasons,\n    name=\"Context Relevance\"\n).on_input().on(context=lambda x: x[\"contexts\"])\n\n# 示例评估\nquestion = \"什么是神经网络？\"\ncontexts = [\"神经网络是一种计算模型。\", \"咖啡是饮料。\"]\n\nresult = provider.context_relevance_with_cot_reasons(\n    question=question,\n    contexts=contexts\n)\nprint(f\"Context Relevance: {result}\")",
