      "code": "# AutoGen v0.4+ - RoundRobinGroupChat 多 Agent 协作\nfrom autogen_agentchat.agents import AssistantAgent\nfrom autogen_agentchat.teams import RoundRobinGroupChat\nfrom autogen_ext.models.openai import OpenAIChatCompletionClient\n\nmodel_client = OpenAIChatCompletionClient(model=\"gpt-4o\")\n\n# 写代码的工程师 Agent\ncoder = AssistantAgent(\n    name=\"Coder\",\n    model_client=model_client,\n    system_message=\"你是有 10 年经验的 Python 工程师, 负责写代码\"\n)\n\n# 审查代码的资深工程师 Agent\nreviewer = AssistantAgent(\n    name=\"Reviewer\",\n    model_client=model_client,\n    system_message=\"你是严格的代码审查员, 负责挑 bug 和性能问题\"\n)\n\n# 团队协作 - 轮流发言\nteam = RoundRobinGroupChat([coder, reviewer])\nresult = await team.run(task=\"写一个支持并发的 HTTP 服务器\")\nprint(result.messages)",
