      "title": "代码示例 2",
      "code": "# CrewAI 角色化 Agent - 客户支持场景\nfrom crewai import Agent, Task, Crew\n\n# 一线客服\nsupport = Agent(\n    role=\"一线客服\",\n    goal=\"快速回答用户问题\",\n    backstory=\"你是某电商客服, 处理订单查询和物流问题\",\n    tools=[]  # 实际: order_query, logistics_query\n)\n\n# 技术专家\ntech_expert = Agent(\n    role=\"技术专家\",\n    goal=\"解决技术问题\",\n    backstory=\"你是工程师, 处理退款和系统错误\",\n    tools=[]\n)\n\n# 任务 1: 一线响应\ntask1 = Task(\n    description=\"回复用户: '我的订单还没到'\",\n    agent=support\n)\n\n# 任务 2: 升级处理\ntask2 = Task(\n    description=\"处理升级工单: '系统报错 500'\",\n    agent=tech_expert\n)\n\ncrew = Crew(\n    agents=[support, tech_expert],\n    tasks=[task1, task2],\n    process=Process.sequential\n)\n\nresult = crew.kickoff()",
