        "code": "# 文件: orpo_train.py\n# ORPO 单阶段训练: SFT + 偏好优化\nimport torch\nfrom datasets import load_dataset\nfrom transformers import AutoModelForCausalLM, AutoTokenizer\nfrom trl import CPOTrainer, CPOConfig\n\n# 注意: ORPO 可以直接从预训练模型开始, 不需要 SFT\nmodel = AutoModelForCausalLM.from_pretrained(\"Qwen/Qwen2-7B-Instruct\", torch_dtype=torch.bfloat16)\ntokenizer = AutoTokenizer.from_pretrained(\"Qwen/Qwen2-7B-Instruct\")\n\ndataset = load_dataset(\"HuggingFaceH4/ultrafeedback_binarized\", split=\"train_prefs[:5000]\")\n\nconfig = CPOConfig(\n    output_dir=\"./qwen2-7b-orpo\",\n    num_train_epochs=2,\n    per_device_train_batch_size=2, gradient_accumulation_steps=8,\n    learning_rate=1e-6, bf16=True,\n    loss_type=\"orpo\",                 # 关键: 切换为 ORPO\n    beta=0.1,                          # ORPO 的 beta 控制胜率比缩放\n    cpo_alpha=1.0,                     # 控制 SFT 损失的权重 (λ)\n    max_length=1024, max_prompt_length=512,\n)\n# ORPO 不需要 ref_model 参数\ntrainer = CPOTrainer(\n    model=model,\n    args=config, train_dataset=dataset.map(lambda x: {\n        \"prompt\": x[\"prompt\"], \"chosen\": x[\"chosen\"][-1][\"content\"],\n        \"rejected\": x[\"rejected\"][-1][\"content\"]}),\n    processing_class=tokenizer,\n)\ntrainer.train()",
