        "title": "代码示例 6",
        "code": "# 文件: algo_bench.py\n# 对比 DPO / KTO / SimPO / ORPO 的训练显存与收敛步数\nimport torch, time, gc\nfrom transformers import AutoModelForCausalLM, AutoTokenizer\nfrom trl import DPOTrainer, KTOTrainer, CPOTrainer, DPOConfig, KTOConfig, CPOConfig\nfrom datasets import Dataset\n\nmodel_path = \"Qwen/Qwen2-0.5B-Instruct\"\nref_model = AutoModelForCausalLM.from_pretrained(model_path, torch_dtype=torch.bfloat16).cuda()\ntokenizer = AutoTokenizer.from_pretrained(model_path)\nif tokenizer.pad_token is None: tokenizer.pad_token = tokenizer.eos_token\n\n# 构造小数据集\ndata = Dataset.from_list([{\n    \"prompt\": \"问题\", \"chosen\": \"好答案, 详细且准确。\", \"rejected\": \"差答案。\"\n}] * 100)\n\ndef bench(trainer_cls, config):\n    gc.collect(); torch.cuda.empty_cache()\n    m = AutoModelForCausalLM.from_pretrained(model_path, torch_dtype=torch.bfloat16).cuda()\n    torch.cuda.reset_peak_memory_stats()\n    t0 = time.time()\n    if trainer_cls is CPOTrainer:\n        # SimPO / ORPO 不需要 ref\n        trainer = trainer_cls(model=m, ref_model=None, args=config,\n            train_dataset=data, processing_class=tokenizer)\n    else:\n        trainer = trainer_cls(model=m, ref_model=ref_model, args=config,\n            train_dataset=data, processing_class=tokenizer)\n    trainer.train()\n    peak = torch.cuda.max_memory_allocated() / 1e9\n    print(f\"{trainer_cls.__name__}: 100步 {time.time()-t0:.1f}s, 显存 {peak:.2f}GB\")\n    del m, trainer; gc.collect(); torch.cuda.empty_cache()\n\nbench(DPOTrainer, DPOConfig(output_dir=\"/tmp/d\", per_device_train_batch_size=1,\n    learning_rate=1e-6, bf16=True, beta=0.1, max_length=128, num_train_epochs=1))\nbench(KTOTrainer, KTOConfig(output_dir=\"/tmp/k\", per_device_train_batch_size=1,\n    learning_rate=1e-6, bf16=True, beta=0.1, max_length=128, num_train_epochs=1))\n# SimPO / ORPO 通过 CPOTrainer 切换 loss_type\nbench(CPOTrainer, CPOConfig(output_dir=\"/tmp/s\", per_device_train_batch_size=1,\n    learning_rate=1e-6, bf16=True, beta=2.0, loss_type=\"simpo\",\n    cpo_alpha=0.0, max_length=128, num_train_epochs=1))\nbench(CPOTrainer, CPOConfig(output_dir=\"/tmp/o\", per_device_train_batch_size=1,\n    learning_rate=1e-6, bf16=True, beta=0.1, loss_type=\"orpo\",\n    cpo_alpha=1.0, max_length=128, num_train_epochs=1))",
