        "title": "代码示例 1",
        "code": "# ReAct 循环伪代码\ndef react_loop(question, max_steps=10):\n    \"\"\"\n    ReAct 主循环：Thought → Action → Observation → ... → Finish\n    \"\"\"\n    trajectory = []\n    step = 0\n    \n    while step < max_steps:\n        # 步骤1：生成 Thought（推理）\n        thought = generate_thought(question, trajectory)\n        trajectory.append((\"Thought\", thought))\n        \n        # 步骤2：生成 Action（行动）\n        action = generate_action(thought, trajectory)\n        trajectory.append((\"Action\", action))\n        \n        # 步骤3：检查是否完成\n        if action == \"Finish\":\n            final_answer = extract_answer(thought)\n            return final_answer, trajectory\n        \n        # 步骤4：执行行动并获取 Observation（观察）\n        observation = execute_action(action)\n        trajectory.append((\"Observation\", observation))\n        \n        step += 1\n    \n    # 超时处理\n    return \"Timeout\", trajectory",
