        "title": "代码示例 5",
        "code": "{\n  \"mcpServers\": {\n    \"my-helper-server\": {\n      \"command\": \"python\",\n      \"args\": [\n        \"/absolute/path/to/your/my_mcp_server.py\"\n      ],\n      \"env\": {}\n    },\n    \"github-server\": {\n      \"command\": \"npx\",\n      \"args\": [\n        \"-y\",\n        \"@anthropic-ai/mcp-server-github\"\n      ],\n      \"env\": {\n        \"GITHUB_TOKEN\": \"your_github_personal_access_token\"\n      }\n    },\n    \"filesystem-server\": {\n      \"command\": \"npx\",\n      \"args\": [\n        \"-y\",\n        \"@anthropic-ai/mcp-server-filesystem\",\n        \"/allowed/path/for/access\"\n      ]\n    }\n  }\n}",
        "language": "json",
