        "title": "代码示例 2",
        "code": "import json\nimport random\n\n# 模拟 AgentBench 的 Tool-Query 场景\nclass SimpleToolEnv:\n    \"\"\"一个模拟的工具调用环境\"\"\"\n    def __init__(self):\n        self.tools = {\n            \"get_weather\": {\"city\": \"str\", \"date\": \"str\"},\n            \"calculate\": {\"expression\": \"str\"},\n            \"get_time\": {\"timezone\": \"str\"},\n        }\n\n    def execute_tool(self, tool_name, params):\n        \"\"\"模拟执行工具并返回结果\"\"\"\n        if tool_name == \"get_weather\":\n            return f\"Weather in {params['city']} on {params['date']}: Sunny, 25°C\"\n        elif tool_name == \"calculate\":\n            try:\n                result = eval(params['expression'])\n                return f\"Result: {result}\"\n            except Exception as e:\n                return f\"Error: {e}\"\n        elif tool_name == \"get_time\":\n            return f\"Current time in {params['timezone']}: 12:00 PM\"\n        else:\n            return f\"Tool '{tool_name}' not found.\"\n\ndef evaluate_agent(agent_func, env, test_cases):\n    \"\"\"评估 Agent 的任务完成率和工具调用准确率\"\"\"\n    total_tasks = len(test_cases)\n    success_tasks = 0\n    total_tool_calls = 0\n    correct_tool_calls = 0\n\n    for task, expected_tool, expected_params in test_cases:\n        print(f\"\\n--- Task: {task} ---\")\n        # Agent 执行任务\n        result = agent_func(task, env)\n        print(f\"Agent Result: {result}\")\n\n        # 检查任务完成率 (这里简化：如果 Agent 返回了非 None 结果，认为成功)\n        if result is not None:\n            success_tasks += 1\n\n        # 检查工具调用准确率 (这里简化：我们假设 Agent 的轨迹中包含工具调用信息)\n        # 在实际中，需要解析 Agent 的完整轨迹\n        if 'tool_calls' in result:\n            for call in result['tool_calls']:\n                total_tool_calls += 1\n                if call['name'] == expected_tool and call['params'] == expected_params:\n                    correct_tool_calls += 1\n\n    task_success_rate = success_tasks / total_tasks\n    tool_accuracy = correct_tool_calls / total_tool_calls if total_tool_calls > 0 else 0\n\n    print(\"\\n===== Evaluation Results =====\")\n    print(f\"Task Success Rate: {task_success_rate:.2f} ({success_tasks}/{total_tasks})\")\n    print(f\"Tool Selection Accuracy: {tool_accuracy:.2f} ({correct_tool_calls}/{total_tool_calls})\")\n    return task_success_rate, tool_accuracy\n\n# 一个简单的 Agent 实现 (用于演示)\ndef simple_agent(task, env):\n    \"\"\"一个非常简单的 Agent，尝试解析任务并调用工具\"\"\"\n    tool_calls = []\n    result = None\n\n    if \"weather\" in task.lower():\n        # 解析城市和日期 (简化)\n        parts = task.split()\n        city = parts[2] if len(parts) > 2 else \"Beijing\"\n        date = parts[4] if len(parts) > 4 else \"today\"\n        tool_name = \"get_weather\"\n        params = {\"city\": city, \"date\": date}\n        tool_calls.append({\"name\": tool_name, \"params\": params})\n        result = env.execute_tool(tool_name, params)\n    elif \"calculate\" in task.lower():\n        # 解析表达式\n        expression = task.split(\"calculate\")[-1].strip()\n        tool_name = \"calculate\"\n        params = {\"expression\": expression}\n        tool_calls.append({\"name\": tool_name, \"params\": params})\n        result = env.execute_tool(tool_name, params)\n    else:\n        result = \"I cannot handle this task.\"\n\n    return {\"result\": result, \"tool_calls\": tool_calls}\n\n# 测试用例\ntest_cases = [\n    (\"What is the weather in Shanghai today?\", \"get_weather\", {\"city\": \"Shanghai\", \"date\": \"today\"}),\n    (\"Please calculate 2 + 2\", \"calculate\", {\"expression\": \"2 + 2\"}),\n    (\"What is the weather in Beijing tomorrow?\", \"get_weather\", {\"city\": \"Beijing\", \"date\": \"tomorrow\"}),\n]\n\nenv = SimpleToolEnv()\nevaluate_agent(simple_agent, env, test_cases)",
