        "title": "代码示例 4",
        "code": "import docker\nimport os\nimport tempfile\n\ndef run_in_sandbox(command_to_run, timeout=10):\n    \"\"\"\n    在 Docker 沙箱中执行一个命令。\n    沙箱配置：\n    - 只读根文件系统\n    - 限制内存和 CPU\n    - 移除所有 Linux 能力\n    - 断开网络\n    - 以非 root 用户运行\n    \"\"\"\n    client = docker.from_env()\n\n    # 创建一个临时目录，用于挂载必要的文件（如果需要）\n    # 这里我们使用一个简单的 \"hello world\" 镜像\n    image = \"alpine:latest\"\n\n    # 配置容器\n    container_config = {\n        'image': image,\n        'command': command_to_run,\n        'read_only': True,  # 只读文件系统\n        'mem_limit': '128m',  # 内存限制\n        'cpu_period': 100000,\n        'cpu_quota': 50000,  # 限制为 0.5 个 CPU\n        'network_disabled': True,  # 禁用网络\n        'cap_drop': ['ALL'],  # 移除所有能力\n        'user': 'nobody',  # 以非 root 用户运行\n        'remove': True,  # 容器退出后自动删除\n    }\n\n    try:\n        # 创建并启动容器\n        container = client.containers.create(**container_config)\n        container.start()\n\n        # 等待容器完成\n        result = container.wait(timeout=timeout)\n\n        # 获取日志\n        logs = container.logs(stdout=True, stderr=True).decode('utf-8')\n\n        return {\n            \"exit_code\": result['StatusCode'],\n            \"logs\": logs,\n            \"success\": result['StatusCode'] == 0\n        }\n    except docker.errors.ContainerError as e:\n        return {\"exit_code\": -1, \"logs\": str(e), \"success\": False}\n    except docker.errors.APIError as e:\n        return {\"exit_code\": -1, \"logs\": f\"Docker API Error: {e}\", \"success\": False}\n    except Exception as e:\n        return {\"exit_code\": -1, \"logs\": f\"Unexpected Error: {e}\", \"success\": False}\n\n# 测试沙箱\nif __name__ == \"__main__\":\n    # 安全命令\n    safe_command = \"echo 'Hello from sandbox!'\"\n    result = run_in_sandbox(safe_command)\n    print(f\"Safe Command Result: {result}\")\n\n    # 危险命令 (应该被沙箱限制)\n    dangerous_command = \"rm -rf /\"\n    result = run_in_sandbox(dangerous_command)\n    print(f\"Dangerous Command Result: {result}\")\n\n    # 尝试逃逸 (应该失败)\n    escape_command = \"cat /etc/passwd\"\n    result = run_in_sandbox(escape_command)\n    print(f\"Escape Attempt Result: {result}\")",
