        "title": "代码示例 5",
        "code": "import json\nimport logging\nimport datetime\nfrom typing import Dict, Any\n\n# 配置结构化日志\nlogging.basicConfig(\n    level=logging.INFO,\n    format='%(asctime)s - %(name)s - %(levelname)s - %(message)s',\n    handlers=[\n        logging.FileHandler('agent_audit.log'),\n        logging.StreamHandler()  # 同时输出到控制台\n    ]\n)\nlogger = logging.getLogger(\"AgentAudit\")\n\nclass AuditLogger:\n    \"\"\"Agent 审计日志记录器\"\"\"\n\n    def __init__(self, agent_id: str):\n        self.agent_id = agent_id\n\n    def _log(self, event_type: str, data: Dict[str, Any], level=logging.INFO):\n        \"\"\"记录一条结构化日志\"\"\"\n        log_entry = {\n            \"timestamp\": datetime.datetime.utcnow().isoformat() + \"Z\",\n            \"agent_id\": self.agent_id,\n            \"event_type\": event_type,\n            **data\n        }\n        logger.log(level, json.dumps(log_entry))\n\n        # 如果是告警级别，触发额外的告警机制\n        if level >= logging.WARNING:\n            self._trigger_alert(log_entry)\n\n    def _trigger_alert(self, log_entry: Dict[str, Any]):\n        \"\"\"触发告警 (这里模拟发送邮件或 webhook)\"\"\"\n        print(f\"\\n*** ALERT ***: {log_entry['event_type']} - {log_entry.get('message', '')}\")\n        # 在实际中，这里会调用告警 API，如 Slack Webhook、PagerDuty 等\n        # send_alert_to_ops_team(log_entry)\n\n    def log_user_input(self, session_id: str, user_input: str):\n        self._log(\"USER_INPUT\", {\n            \"session_id\": session_id,\n            \"input\": user_input\n        })\n\n    def log_agent_thought(self, session_id: str, thought: str):\n        self._log(\"AGENT_THOUGHT\", {\n            \"session_id\": session_id,\n            \"thought\": thought\n        })\n\n    def log_tool_call(self, session_id: str, tool_name: str, params: Dict, result: Any):\n        self._log(\"TOOL_CALL\", {\n            \"session_id\": session_id,\n            \"tool_name\": tool_name,\n            \"params\": params,\n            \"result\": str(result)[:200]  # 限制结果长度\n        })\n\n    def log_agent_output(self, session_id: str, output: str):\n        self._log(\"AGENT_OUTPUT\", {\n            \"session_id\": session_id,\n            \"output\": output\n        })\n\n    def log_error(self, session_id: str, error_message: str):\n        self._log(\"ERROR\", {\n            \"session_id\": session_id,\n            \"message\": error_message\n        }, level=logging.ERROR)\n\n    def log_security_alert(self, session_id: str, alert_type: str, details: str):\n        self._log(\"SECURITY_ALERT\", {\n            \"session_id\": session_id,\n            \"alert_type\": alert_type,\n            \"details\": details\n        }, level=logging.WARNING)\n\n# 模拟一个 Agent 会话\ndef simulate_agent_session():\n    audit = AuditLogger(agent_id=\"FinBot-v2\")\n\n    session_id = \"session_12345\"\n\n    # 用户输入\n    audit.log_user_input(session_id, \"What is my account balance?\")\n\n    # Agent 思考\n    audit.log_agent_thought(session_id, \"User wants account balance. I need to call the query_balance tool.\")\n\n    # 工具调用 (正常)\n    audit.log_tool_call(session_id, \"query_balance\", {\"user_id\": \"user_001\"}, {\"balance\": 1000.50})\n\n    # Agent 输出\n    audit.log_agent_output(session_id, \"Your account balance is $1000.50.\")\n\n    # 模拟一个错误\n    audit.log_error(session_id, \"Database connection timeout.\")\n\n    # 模拟一个安全告警 (例如检测到 Prompt Injection)\n    audit.log_security_alert(session_id, \"POTENTIAL_INJECTION\", \"Detected 'ignore previous instructions' in user input.\")\n\nif __name__ == \"__main__\":\n    simulate_agent_session()\n    print(\"\\nAudit log has been written to 'agent_audit.log'\")",
        "language": "python",
        "repo": "None",
        "install_cmd": "pip install openai transformers"
